const DEFAULT_CHAT_ID = '730354404';
const REMINDER_TIME = '08:00';
const REMINDER_TIMEZONE = 'Europe/Madrid';

const getVar = (key) => {
  if (typeof $vars !== 'undefined' && $vars[key] != null) {
    return String($vars[key]);
  }
  if (typeof $env !== 'undefined' && $env[key] != null) {
    return String($env[key]);
  }
  if (typeof process !== 'undefined' && process.env && process.env[key] != null) {
    return String(process.env[key]);
  }
  return '';
};

const isTruthy = (value) => ['1', 'true', 'yes', 'on'].includes(String(value).toLowerCase());

const getLocalNow = (timeZone) => {
  const now = new Date();
  const formatter = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    weekday: 'long',
  });

  const parts = formatter.formatToParts(now).reduce((acc, part) => {
    if (part.type !== 'literal') {
      acc[part.type] = part.value;
    }
    return acc;
  }, {});

  return {
    iso: now.toISOString(),
    date: `${parts.year}-${parts.month}-${parts.day}`,
    time: `${parts.hour}:${parts.minute}`,
    weekday: parts.weekday || '',
  };
};

const previewEnabled = isTruthy(getVar('RC_TELEGRAM_PREVIEW_MODE'));
const previewChatRaw = getVar('RC_TELEGRAM_PREVIEW_CHAT_ID').trim();
if (previewEnabled && !previewChatRaw) {
  throw new Error('RC_TELEGRAM_PREVIEW_CHAT_ID is required when RC_TELEGRAM_PREVIEW_MODE is enabled.');
}

const reminderEnabled = isTruthy(getVar('RC_REMINDER_ENABLED'));
if (!reminderEnabled) {
  return [];
}

let localNow;
try {
  localNow = getLocalNow(REMINDER_TIMEZONE);
} catch (error) {
  throw new Error(`Invalid reminder timezone: ${REMINDER_TIMEZONE}`);
}

const forceSend = isTruthy(getVar('RC_REMINDER_FORCE_SEND'));
const targetChatId = previewEnabled ? previewChatRaw : DEFAULT_CHAT_ID;
const runId = `reminder-${localNow.date}-${Math.random().toString(36).slice(2, 10)}`;

return [{
  json: {
    runId,
    status: 'reminder',
    createdAt: localNow.iso,
    chatId: targetChatId,
    previewMode: previewEnabled,
    previewChatId: targetChatId,
    reminderEnabled,
    reminderDate: localNow.date,
    reminderWeekday: localNow.weekday,
    reminderTime: REMINDER_TIME,
    reminderTimezone: REMINDER_TIMEZONE,
    reminderForceSend: forceSend,
    reminderKey: `${targetChatId}:${localNow.date}`,
    reminderOptInUsersCount: 1,
    reminder_opt_in_users_count: 1,
  }
}];

const contextItems = $items('Build Reminder Context');
if (!contextItems.length) {
  return [];
}

const context = contextItems[0].json || {};

const snapshotDocs = $items('Read Latest Plan Snapshot')
  .map((item) => item.json || {})
  .filter((doc) => doc && Object.keys(doc).length > 0);

const sentDocs = items
  .map((item) => item.json || {})
  .filter((doc) => doc && Object.keys(doc).length > 0);

const planSnapshot = snapshotDocs[0] || {};
const activityPlan = (planSnapshot.activityPlan && typeof planSnapshot.activityPlan === 'object')
  ? planSnapshot.activityPlan
  : {};
const days = Array.isArray(activityPlan.days) ? activityPlan.days : [];

const normalizeDay = (value) => {
  const text = String(value || '').trim().toLowerCase();
  if (!text) return '';
  const map = {
    monday: 'monday',
    lunes: 'monday',
    tuesday: 'tuesday',
    martes: 'tuesday',
    wednesday: 'wednesday',
    miercoles: 'wednesday',
    'miércoles': 'wednesday',
    thursday: 'thursday',
    jueves: 'thursday',
    friday: 'friday',
    viernes: 'friday',
    saturday: 'saturday',
    sabado: 'saturday',
    'sábado': 'saturday',
    sunday: 'sunday',
    domingo: 'sunday',
  };
  return map[text] || text;
};

const todayDayKey = normalizeDay(context.reminderWeekday);
let session = days.find((day) => String(day.date || '') === String(context.reminderDate || '')) || null;
if (!session && todayDayKey) {
  session = days.find((day) => normalizeDay(day.day) === todayDayKey) || null;
}

const alreadySent = sentDocs.length > 0;
let shouldSend = false;
let deliveryStatus = 'skipped';
let deliveryReason = 'unknown';

if (!Array.isArray(days) || days.length === 0) {
  deliveryStatus = 'skipped_no_plan';
  deliveryReason = 'missing_plan_days';
} else if (!session) {
  deliveryStatus = 'skipped_no_session';
  deliveryReason = 'missing_daily_session';
} else if (alreadySent) {
  deliveryStatus = 'skipped_already_sent';
  deliveryReason = 'already_sent_today';
} else {
  shouldSend = true;
  deliveryStatus = 'pending';
  deliveryReason = 'ready_to_send';
}

const esc = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const lines = [
  context.previewMode ? '🧪 <b>Preview mode</b>' : null,
  `⏰ <b>Training reminder</b> (${esc(context.reminderDate)})`,
];

if (session) {
  lines.push(`🏃 <b>${esc(session.activity || 'Session')}</b>`);
  if (session.distance_time) {
    lines.push(`Duration: ${esc(session.distance_time)}`);
  }
  if (session.intensity && session.intensity !== '-') {
    lines.push(`Intensity: ${esc(session.intensity)}`);
  }
  if (session.goal) {
    lines.push(`Goal: ${esc(session.goal)}`);
  }
  if (session.note) {
    lines.push(`Note: ${esc(session.note)}`);
  }
} else {
  lines.push('No planned session found for today.');
}

if (!shouldSend && deliveryStatus === 'skipped_already_sent') {
  lines.push('Reminder already sent today.');
}

return [{
  json: {
    runId: context.runId,
    status: context.status,
    createdAt: context.createdAt,
    chatId: context.chatId,
    previewMode: context.previewMode,
    previewChatId: context.previewChatId,
    reminderDate: context.reminderDate,
    reminderWeekday: context.reminderWeekday,
    reminderTime: context.reminderTime,
    reminderTimezone: context.reminderTimezone,
    reminderForceSend: context.reminderForceSend,
    reminderKey: context.reminderKey,
    reminderEnabled: context.reminderEnabled,
    reminderOptInUsersCount: context.reminderOptInUsersCount,
    reminder_opt_in_users_count: context.reminder_opt_in_users_count,
    reminderSentCount: shouldSend ? 1 : 0,
    reminder_sent_count: shouldSend ? 1 : 0,
    shouldSend,
    deliveryStatus,
    deliveryReason,
    session,
    text: lines.filter(Boolean).join('\n'),
  }
}];

const baseItems = $items('Build Reminder Message');
if (!baseItems.length) {
  return [];
}

const base = baseItems[0].json || {};
const incoming = (items[0] && items[0].json && typeof items[0].json === 'object') ? items[0].json : {};
const incomingHasPayload = Object.prototype.hasOwnProperty.call(incoming, 'shouldSend');

let deliveryStatus = base.deliveryStatus || 'skipped';
let deliveryReason = base.deliveryReason || null;
let reminderSentCount = base.shouldSend ? 1 : 0;
let telegramMessageId = null;
let telegramResponse = null;

if (incomingHasPayload) {
  deliveryStatus = incoming.deliveryStatus || deliveryStatus;
  deliveryReason = incoming.deliveryReason || deliveryReason;
  reminderSentCount = incoming.shouldSend ? 1 : 0;
} else if (base.shouldSend) {
  deliveryStatus = 'sent';
  deliveryReason = 'sent';
  reminderSentCount = 1;
  telegramResponse = incoming;
  if (incoming && incoming.result && incoming.result.message_id != null) {
    telegramMessageId = incoming.result.message_id;
  }
}

const createdAt = new Date().toISOString();

return [{
  json: {
    runId: base.runId || `reminder-${Math.random().toString(36).slice(2, 10)}`,
    status: 'reminder',
    chatId: base.chatId || null,
    previewMode: Boolean(base.previewMode),
    previewChatId: base.previewChatId || null,
    reminderDate: base.reminderDate || null,
    reminderWeekday: base.reminderWeekday || null,
    reminderTime: base.reminderTime || null,
    reminderTimezone: base.reminderTimezone || null,
    reminderForceSend: Boolean(base.reminderForceSend),
    reminderKey: base.reminderKey || null,
    reminderEnabled: Boolean(base.reminderEnabled),
    deliveryStatus,
    deliveryReason,
    session: base.session || null,
    text: base.text || null,
    telegramMessageId,
    telegramResponse,
    reminderSentCount,
    reminder_sent_count: reminderSentCount,
    reminderOptInUsersCount: base.reminderOptInUsersCount === 1 ? 1 : 0,
    reminder_opt_in_users_count: base.reminder_opt_in_users_count === 1 ? 1 : 0,
    createdAt,
  }
}];

const getVar = (key) => {
  if (typeof $vars !== 'undefined' && $vars[key] != null) return String($vars[key]);
  if (typeof $env !== 'undefined' && $env[key] != null) return String($env[key]);
  if (typeof process !== 'undefined' && process.env && process.env[key] != null) return String(process.env[key]);
  return '';
};

const sanitizeLabel = (value) => String(value || 'unknown').toLowerCase().replace(/[^a-z0-9_:.-]+/g, '_').replace(/^_+|_+$/g, '') || 'unknown';

const metricsEnabledRaw = getVar('RC_METRICS_PUSH_ENABLED').trim();
const metricsEnabled = !metricsEnabledRaw || ['1', 'true', 'yes', 'on'].includes(metricsEnabledRaw.toLowerCase());
if (!metricsEnabled) {
  return [];
}

const baseUrl = getVar('RC_PUSHGATEWAY_URL').trim();
if (!baseUrl) {
  return [];
}

const envLabel = sanitizeLabel(getVar('RC_METRICS_ENV').trim() || 'prod');
const metricName = 'running_coach_run_timestamp_seconds';
const workflow = sanitizeLabel('running_coach_reminder');
const status = sanitizeLabel(($json.deliveryStatus || '').toLowerCase() === 'failed' ? 'failure' : 'success');
const timestampSec = Math.floor(Date.now() / 1000);
const metricBody = `${metricName} ${timestampSec}\n`;
const root = baseUrl.replace(/\/+$/, '');
const metricsEndpoint = `${root}/metrics/job/n8n_workflows/workflow/${encodeURIComponent(workflow)}/status/${encodeURIComponent(status)}/env/${encodeURIComponent(envLabel)}`;

return [{
  json: {
    workflow,
    status,
    env: envLabel,
    metricName,
    timestampSec,
    metricBody,
    metricsEndpoint,
  }
}];
